// Previous children (what is in the current Fiber tree)
[
  <Item key="alice" name="Alice" />,
  <Item key="bob"   name="Bob"   />,
  <Item key="carol" name="Carol" />,
]

// New children (what this render returns)
[
  <Item key="zara"  name="Zara"  />,  // key not in map → INSERT
  <Item key="alice" name="Alice" />,  // key in map     → UPDATE, move to pos 1
  <Item key="bob"   name="Bob"   />,  // key in map     → UPDATE, keep at pos 2
                                       // key="carol" left in map → DELETE
]

// DOM operations:
// 1. Remove <carol> Fiber (run useEffect cleanup)
// 2. Insert new DOM node for <zara> at position 0
// 3. <alice> and <bob> DOM nodes unchanged (no prop diffs)

function SelectableItem({ name }) {
  const [selected, setSelected] = useState(false);
  return (
    <li
      style={{ background: selected ? '#eee' : 'transparent' }}
      onClick={() => setSelected(s => !s)}
    >
      {name}
    </li>
  );
}

function BadList() {
  const [items, setItems] = useState(['Alice', 'Bob', 'Carol']);
  return (
    <ul>
      {/* No keys — state is tied to position */}
      {items.map(name => <SelectableItem name={name} />)}
    </ul>
  );
}
// Select "Alice" (pos 0). Prepend "Zara".
// Result: "Zara" appears selected (it moved to pos 0 and inherited Alice's state).
// Alice's selected state is gone — her Fiber was not reused.

function GoodList() {
  const [items, setItems] = useState([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
    { id: 3, name: 'Carol' },
  ]);
  return (
    <ul>
      {/* Stable ID keys — state stays with the right item */}
      {items.map(item => <SelectableItem key={item.id} name={item.name} />)}
    </ul>
  );
}
// Select "Alice" (key=1). Prepend { id: 4, name: 'Zara' }.
// Result: "Zara" is unselected (new Fiber). "Alice" is still selected (same Fiber).

// When you have no better key than the content itself,
// ensure uniqueness by combining fields:
messages.map(msg => (
  <Message key={`${msg.senderId}:${msg.timestamp}`} message={msg} />
))

// Or generate stable IDs at creation time (not at render time):
function addItem(text) {
  setItems(prev => [...prev, { id: crypto.randomUUID(), text }]);
}

// Without key: switching users reuses the ProfileForm Fiber.
// The form fields keep their previous values until onChange handlers update them.
function App({ userId }) {
  return <ProfileForm userId={userId} />;
}

// With key: switching userId destroys the old Fiber and creates a new one.
// All useState is re-initialized to its initial value.
function App({ userId }) {
  return <ProfileForm key={userId} userId={userId} />;
}

// Real example: tab content that should reset when switching tabs
function TabPanel({ activeTab, tabs }) {
  return tabs.map(tab => (
    tab.id === activeTab && (
      // key=activeTab resets the panel's scroll position,
      // form state, and open accordions when the tab changes
      <ContentPanel key={activeTab} content={tab.content} />
    )
  ));
}

function SortableList({ items }) {
  const [sortDir, setSortDir] = useState('asc');
  const sorted = [...items].sort((a, b) =>
    sortDir === 'asc' ? a.name.localeCompare(b.name) : b.name.localeCompare(a.name)
  );

  return (
    <>
      <button onClick={() => setSortDir(d => d === 'asc' ? 'desc' : 'asc')}>
        Sort {sortDir === 'asc' ? '↑' : '↓'}
      </button>
      <ul>
        {sorted.map(item => (
          // Keys let React track which DOM node belongs to which item
          // across the sort — it moves existing nodes rather than updating text
          <li key={item.id}>
            <ItemRow item={item} />
          </li>
        ))}
      </ul>
    </>
  );
}

function DefinitionList({ entries }) {
  return (
    <dl>
      {entries.map(entry => (
        // The shorthand <> cannot have a key — use React.Fragment explicitly
        <React.Fragment key={entry.id}>
          <dt>{entry.term}</dt>
          <dd>{entry.definition}</dd>
        </React.Fragment>
      ))}
    </dl>
  );
}

// Without the key, prepending an entry would cause every
// dt/dd pair to update its text content (positional match).
// With the key, React knows which dt/dd pair belongs to which entry.

// Toggling between two different views of the same data
function Inspector({ item }) {
  const [mode, setMode] = useState('view');

  return (
    <div>
      <button onClick={() => setMode(m => m === 'view' ? 'edit' : 'view')}>
        {mode === 'view' ? 'Edit' : 'Cancel'}
      </button>
      {mode === 'view'
        ? <ViewPanel key="view" item={item} />
        : <EditPanel key="edit"  item={item} />
      }
    </div>
  );
}
// Without keys: ViewPanel and EditPanel share position 1.
// If they are different types, React unmounts+remounts automatically.
// If they happen to be the same type (e.g. both render a <form>),
// without keys React reuses the Fiber and state bleeds between modes.
// Explicit keys guarantee separate Fibers regardless of type.

// key is not accessible as props.key — React strips it
function Item({ key, name }) {         // key is always undefined here
  console.log(key);                    // undefined
  return <li>{name}</li>;
}

// If you need the key value inside the component, pass it twice:
items.map(item => (
  <Item key={item.id} id={item.id} name={item.name} />
))

// Now props.id is accessible:
function Item({ id, name }) {
  console.log(id);  // correct value
  return <li data-id={id}>{name}</li>;
}

// Diagnostic: add a useEffect that logs mount/unmount
function Item({ id, name }) {
  useEffect(() => {
    console.log(`mounted: key=${id}`);
    return () => console.log(`unmounted: key=${id}`);
  }, [id]);

  return <li>{name}</li>;
}
// If you see rapid mount/unmount logs for stable items,
// the parent is either using unstable keys or defining
// the component inside another component's render function.

// Scenario: large list, one item updates its text
// With stable keys: React calls every Item() function (all re-render),
// but finds zero prop diffs for the unchanged items → zero DOM writes

// To skip even the function call, wrap with React.memo:
const Item = React.memo(function Item({ id, name, selected }) {
  return <li data-selected={selected}>{name}</li>;
});

// Now: if the parent re-renders but an item's id/name/selected are unchanged,
// React skips calling Item() entirely — no virtual DOM node created at all.
// This is the actual performance win, not the key.

// Keys and React.memo complement each other:
// - Keys: stable identity (correct state association, minimal DOM ops)
// - React.memo: stable output (skip render for unchanged items)
items.map(item => (
  <Item key={item.id} id={item.id} name={item.name} selected={item.selected} />
))

import { AnimatePresence, motion } from 'framer-motion';

function NotificationList({ notifications }) {
  return (
    // AnimatePresence watches for children being added/removed
    // Keys are required so it can track which item exits
    <AnimatePresence>
      {notifications.map(n => (
        <motion.div
          key={n.id}                      // stable key → consistent identity
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, x: 100 }}   // runs when this key disappears
        >
          {n.message}
        </motion.div>
      ))}
    </AnimatePresence>
  );
}
// Dismissing notification id=3:
// - id=3 key disappears from the new children list
// - AnimatePresence sees the Fiber unmounting and runs the exit animation
// - After the animation, the DOM node is removed
// Without stable keys, AnimatePresence cannot match exit animations to items.

import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';

function Counter({ initialValue = 0 }) {
  const [count, setCount] = useState(initialValue);
  return (
    <div>
      <span>{count}</span>
      <button onClick={() => setCount(c => c + 1)}>+</button>
    </div>
  );
}

test('stable key preserves state across re-renders', async () => {
  const { rerender } = render(
    <ul>
      <li><Counter key="a" /></li>
      <li><Counter key="b" /></li>
    </ul>
  );

  // Increment first counter
  await userEvent.click(screen.getAllByRole('button')[0]);
  expect(screen.getAllByText('1')).toHaveLength(1);

  // Re-render with same keys — state preserved
  rerender(
    <ul>
      <li><Counter key="a" /></li>
      <li><Counter key="b" /></li>
    </ul>
  );
  expect(screen.getAllByText('1')).toHaveLength(1); // still 1
});

test('changed key resets state', async () => {
  const { rerender } = render(<Counter key="v1" />);
  await userEvent.click(screen.getByRole('button'));
  expect(screen.getByText('1')).toBeInTheDocument();

  // Different key → unmount + remount
  rerender(<Counter key="v2" />);
  expect(screen.getByText('0')).toBeInTheDocument(); // reset
});
